import { describe, it, expect, beforeEach } from 'vitest'
import { screen } from '@testing-library/react'
import { MemoryRouter } from 'react-router-dom'
import { MantineProvider } from '@mantine/core'
import { render } from '@testing-library/react'
import { theme } from '@/theme'
import { Home } from './Home'
import { useAuthStore } from '@/stores/authStore'

function renderHome() {
  return render(
    <MantineProvider theme={theme}>
      <MemoryRouter>
        <Home />
      </MemoryRouter>
    </MantineProvider>,
  )
}

describe('Home', () => {
  beforeEach(() => {
    useAuthStore.setState({ token: null, user: null, loading: false })
  })

  it('renders the hero title', () => {
    renderHome()
    expect(screen.getByText('Your second brain')).toBeInTheDocument()
  })

  it('renders feature cards', () => {
    renderHome()
    expect(screen.getByText('Bookmarks')).toBeInTheDocument()
    expect(screen.getByText('Notes')).toBeInTheDocument()
    expect(screen.getByText('Voice Notes')).toBeInTheDocument()
    expect(screen.getByText('Semantic Search')).toBeInTheDocument()
  })

  it('shows login prompt when not authenticated', () => {
    renderHome()
    expect(screen.getByText('Login to capture')).toBeInTheDocument()
  })

  it('shows capture button when authenticated', () => {
    useAuthStore.setState({ token: 'test-token', user: null, loading: false })
    renderHome()
    expect(screen.getByText('Capture')).toBeInTheDocument()
  })
})

