import { MeQuery } from '@/lib/queries'

const TOKEN_KEY = 'flotsam_token'

export interface User {
  id: string
  email: string
  displayName: string | null
}

interface AuthState {
  token: string | null
  user: User | null
  loading: boolean

  initialize: () => Promise<void>
  setAuth: (token: string, user: User) => void
  logout: () => void
  getToken: () => string | null
}

export const useAuthStore = create<AuthState>()((set, get) => ({
  token: null,
  user: null,
  loading: true,

  initialize: async () => {
    const token = localStorage.getItem(TOKEN_KEY)
    if (!token) {
      set({ loading: false })
      return
    }

    set({ token })

    try {
      const result = await urqlClient.query(MeQuery, {}).toPromise()
      if (result.data?.me) {
        set({
          user: {
            id: result.data.me.id,
            email: result.data.me.email,
            displayName: result.data.me.displayName ?? null,
          },
          loading: false,
        })
      } else {
        // Token is invalid or expired
        get().logout()
        set({ loading: false })
      }
    } catch {
      // Network error or other failure — clear invalid session
      get().logout()
      set({ loading: false })
    }
  },

  setAuth: (token: string, user: User) => {
    localStorage.setItem(TOKEN_KEY, token)
    set({ token, user, loading: false })
  },

  logout: () => {
    localStorage.removeItem(TOKEN_KEY)
    set({ token: null, user: null })
  },

  getToken: () => {
    return get().token
  },
}))

