import { describe, it, expect, beforeEach, vi } from 'vitest'
import { useAuthStore } from './authStore'

// Mock urqlClient
vi.mock('@/lib/urqlClient', () => ({
  urqlClient: {
    query: vi.fn(),
  },
}))

// Import after mock setup
import { urqlClient } from '@/lib/urqlClient'
const mockQuery = vi.mocked(urqlClient.query)

describe('authStore', () => {
  beforeEach(() => {
    useAuthStore.setState({ token: null, user: null, loading: true })
    localStorage.clear()
    vi.clearAllMocks()
  })

  describe('initialize', () => {
    it('sets loading false when no token in storage', async () => {
      await useAuthStore.getState().initialize()

      const state = useAuthStore.getState()
      expect(state.loading).toBe(false)
      expect(state.token).toBeNull()
      expect(state.user).toBeNull()
    })

    it('rehydrates user via me query when token exists', async () => {
      localStorage.setItem('flotsam_token', 'valid-token')
      mockQuery.mockReturnValue({
        toPromise: () =>
          Promise.resolve({
            data: {
              me: { id: '1', email: 'test@example.com', displayName: 'Test User' },
            },
          }),
      } as ReturnType<typeof urqlClient.query>)

      await useAuthStore.getState().initialize()

      const state = useAuthStore.getState()
      expect(state.loading).toBe(false)
      expect(state.token).toBe('valid-token')
      expect(state.user).toEqual({
        id: '1',
        email: 'test@example.com',
        displayName: 'Test User',
      })
    })

    it('clears token when me query returns null', async () => {
      localStorage.setItem('flotsam_token', 'expired-token')
      mockQuery.mockReturnValue({
        toPromise: () => Promise.resolve({ data: { me: null } }),
      } as ReturnType<typeof urqlClient.query>)

      await useAuthStore.getState().initialize()

      const state = useAuthStore.getState()
      expect(state.loading).toBe(false)
      expect(state.token).toBeNull()
      expect(state.user).toBeNull()
      expect(localStorage.getItem('flotsam_token')).toBeNull()
    })

    it('clears token on network error', async () => {
      localStorage.setItem('flotsam_token', 'some-token')
      mockQuery.mockReturnValue({
        toPromise: () => Promise.reject(new Error('Network error')),
      } as ReturnType<typeof urqlClient.query>)

      await useAuthStore.getState().initialize()

      const state = useAuthStore.getState()
      expect(state.loading).toBe(false)
      expect(state.token).toBeNull()
      expect(state.user).toBeNull()
    })
  })

  describe('setAuth', () => {
    it('stores token and user', () => {
      useAuthStore.getState().setAuth('new-token', {
        id: '2',
        email: 'user@example.com',
        displayName: null,
      })

      const state = useAuthStore.getState()
      expect(state.token).toBe('new-token')
      expect(state.user?.email).toBe('user@example.com')
      expect(state.loading).toBe(false)
      expect(localStorage.getItem('flotsam_token')).toBe('new-token')
    })
  })

  describe('logout', () => {
    it('clears token and user', () => {
      useAuthStore.setState({
        token: 'tok',
        user: { id: '1', email: 'a@b.com', displayName: null },
      })
      localStorage.setItem('flotsam_token', 'tok')

      useAuthStore.getState().logout()

      const state = useAuthStore.getState()
      expect(state.token).toBeNull()
      expect(state.user).toBeNull()
      expect(localStorage.getItem('flotsam_token')).toBeNull()
    })
  })
})

