import { describe, it, expect, beforeEach } from 'vitest'
import { screen } from '@testing-library/react'
import { MemoryRouter, Routes, Route } from 'react-router-dom'
import { MantineProvider } from '@mantine/core'
import { render } from '@testing-library/react'
import { theme } from '@/theme'
import { ProtectedRoute } from './ProtectedRoute'
import { useAuthStore } from '@/stores/authStore'

function ChildPage() {
  return <div>Protected Content</div>
}

function LoginPage() {
  return <div>Login Page</div>
}

function renderProtected(initialPath = '/protected') {
  return render(
    <MantineProvider theme={theme}>
      <MemoryRouter initialEntries={[initialPath]}>
        <Routes>
          <Route path="/login" element={<LoginPage />} />
          <Route element={<ProtectedRoute />}>
            <Route path="/protected" element={<ChildPage />} />
          </Route>
        </Routes>
      </MemoryRouter>
    </MantineProvider>,
  )
}

describe('ProtectedRoute', () => {
  beforeEach(() => {
    useAuthStore.setState({ token: null, user: null, loading: false })
  })

  it('redirects to login when not authenticated', () => {
    renderProtected()
    expect(screen.getByText('Login Page')).toBeInTheDocument()
    expect(screen.queryByText('Protected Content')).not.toBeInTheDocument()
  })

  it('renders child route when authenticated', () => {
    useAuthStore.setState({ token: 'valid-token', user: null, loading: false })
    renderProtected()
    expect(screen.getByText('Protected Content')).toBeInTheDocument()
    expect(screen.queryByText('Login Page')).not.toBeInTheDocument()
  })

  it('shows loader while session is loading', () => {
    useAuthStore.setState({ token: null, user: null, loading: true })
    renderProtected()
    expect(screen.queryByText('Protected Content')).not.toBeInTheDocument()
    expect(screen.queryByText('Login Page')).not.toBeInTheDocument()
    // Mantine Loader renders an SVG with role="presentation"
    expect(document.querySelector('.mantine-Loader-root')).toBeInTheDocument()
  })
})

